import { useState, useEffect, useCallback, useRef } from "react";
import { Link, useNavigate } from "@tanstack/react-router";
import { Menu, X } from "lucide-react";
import { ThemeToggle } from "./ThemeToggle";

interface NavProps {
  showFeatures?: boolean;
}

export function Nav({ showFeatures = false }: NavProps) {
  const [mobileOpen, setMobileOpen] = useState(false);
  const navigate = useNavigate();
  const closeMobile = () => setMobileOpen(false);
  const mobileMenuRef = useRef<HTMLDivElement>(null);

  // Close mobile menu on resize past breakpoint
  const handleResize = useCallback(() => {
    if (window.innerWidth >= 768) setMobileOpen(false);
  }, []);

  useEffect(() => {
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, [handleResize]);

  // Close mobile menu on click outside or escape
  useEffect(() => {
    if (!mobileOpen) return;
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === "Escape") setMobileOpen(false);
    };
    const handleClickOutside = (e: MouseEvent) => {
      if (mobileMenuRef.current && !mobileMenuRef.current.contains(e.target as Node)) {
        setMobileOpen(false);
      }
    };
    document.addEventListener("keydown", handleEscape);
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("keydown", handleEscape);
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [mobileOpen]);

  const actionButtonClass = "inline-flex shrink-0 items-center justify-center rounded-md text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground disabled:pointer-events-none disabled:opacity-50";

  return (
    <nav
      className="chat-header flex items-center gap-2 border-b border-border shrink-0 px-2 sm:px-4 py-2 h-14 sticky top-0 z-50 bg-background"
    >
      {/* Brand */}
      <Link
        to="/"
        className="inline-flex min-w-0 shrink-0 items-center gap-2 rounded-md px-2 py-1 hover:bg-accent hover:text-accent-foreground"
        aria-label="Go to Keating home"
      >
        <img src="/logo.png" alt="Keating" className="h-7 w-7 rounded object-contain sm:hidden" />
        <span className="hidden sm:inline truncate text-base font-semibold sm:text-lg">Keating</span>
      </Link>

      {/* Desktop navigation */}
      <div className="ml-auto hidden md:flex min-w-0 flex-1 items-center justify-end gap-1 overflow-x-auto">
        <ThemeToggle />
        {showFeatures && (
          <a href="#features" className={`${actionButtonClass} px-2 py-1 font-terminal text-xs`}>
            [FEATURES]
          </a>
        )}
        <Link to="/" className={`${actionButtonClass} px-2 py-1 font-terminal text-xs`}>
          [HOME]
        </Link>
        <Link to="/tutorial" className={`${actionButtonClass} px-2 py-1 font-terminal text-xs`}>
          [TUTORIAL]
        </Link>
        <Link to="/blog" className={`${actionButtonClass} px-2 py-1 font-terminal text-xs`}>
          [BLOG]
        </Link>
        <Link to="/paper" className={`${actionButtonClass} px-2 py-1 font-terminal text-xs`}>
          [PAPER]
        </Link>
        <Link to="/usage" className={`${actionButtonClass} px-2 py-1 font-terminal text-xs`}>
          [USAGE]
        </Link>
        <a
          href="https://github.com/Diogenesoftoronto/keating"
          target="_blank"
          rel="noreferrer"
          className={`${actionButtonClass} px-2 py-1 font-terminal text-xs`}
        >
          [GITHUB]
        </a>
        <button
          className="inline-flex items-center justify-center rounded-md bg-primary px-3 py-1.5 text-xs font-medium text-primary-foreground hover:bg-primary/90 transition-colors"
          onClick={() => navigate({ to: "/chat" })}
        >
          TRY_KEATING
        </button>
      </div>

      {/* Mobile / tablet actions + hamburger */}
      <div className="ml-auto flex md:hidden min-w-0 flex-1 items-center justify-end gap-1">
        <ThemeToggle />
        <button
          className={actionButtonClass}
          title="Menu"
          aria-label="Menu"
          aria-expanded={mobileOpen}
          onClick={() => setMobileOpen((o) => !o)}
        >
          {mobileOpen ? <X size={16} /> : <Menu size={16} />}
        </button>
      </div>

      {/* Mobile dropdown menu */}
      {mobileOpen && (
        <div
          ref={mobileMenuRef}
          className="absolute right-2 top-full z-50 mt-1 w-56 rounded-md border border-border bg-background shadow-lg font-terminal"
          style={{ fontSize: "0.875rem" }}
        >
          <div className="flex flex-col p-1">
            {showFeatures && (
              <a
                href="#features"
                className="flex items-center gap-2 rounded-md px-3 py-2 text-left text-sm hover:bg-accent hover:text-accent-foreground transition-colors"
                onClick={closeMobile}
              >
                Features
              </a>
            )}
            <Link
              to="/"
              className="flex items-center gap-2 rounded-md px-3 py-2 text-left text-sm hover:bg-accent hover:text-accent-foreground transition-colors"
              onClick={closeMobile}
            >
              Home
            </Link>
            <Link
              to="/tutorial"
              className="flex items-center gap-2 rounded-md px-3 py-2 text-left text-sm hover:bg-accent hover:text-accent-foreground transition-colors"
              onClick={closeMobile}
            >
              Tutorial
            </Link>
            <Link
              to="/blog"
              className="flex items-center gap-2 rounded-md px-3 py-2 text-left text-sm hover:bg-accent hover:text-accent-foreground transition-colors"
              onClick={closeMobile}
            >
              Blog
            </Link>
            <Link
              to="/paper"
              className="flex items-center gap-2 rounded-md px-3 py-2 text-left text-sm hover:bg-accent hover:text-accent-foreground transition-colors"
              onClick={closeMobile}
            >
              Paper
            </Link>
            <Link
              to="/usage"
              className="flex items-center gap-2 rounded-md px-3 py-2 text-left text-sm hover:bg-accent hover:text-accent-foreground transition-colors"
              onClick={closeMobile}
            >
              Usage
            </Link>
            <a
              href="https://github.com/Diogenesoftoronto/keating"
              target="_blank"
              rel="noreferrer"
              className="flex items-center gap-2 rounded-md px-3 py-2 text-left text-sm hover:bg-accent hover:text-accent-foreground transition-colors"
              onClick={closeMobile}
            >
              GitHub
            </a>
            <button
              className="mt-1 w-full rounded-md bg-primary px-3 py-2 text-sm font-medium text-primary-foreground hover:bg-primary/90 transition-colors"
              onClick={() => {
                closeMobile();
                navigate({ to: "/chat" });
              }}
            >
              TRY KEATING
            </button>
          </div>
        </div>
      )}
    </nav>
  );
}

