1	import { useCallback, useEffect, useRef, useState } from "react";
2	import { PanelRightClose, Search } from "lucide-react";
3	import { ArtifactViewer } from "./ArtifactViewer";
4	import { KeatingStorage } from "../keating/storage";
5	
6	interface ArtifactSidePanelProps {
7		open: boolean;
8		artifactId?: string;
9		onClose: () => void;
10	}
11	
12	const artifactStorage = new KeatingStorage();
13	
14	const MIN_WIDTH = 288;
15	const MAX_WIDTH = 960;
16	const DEFAULT_WIDTH = 480;
17	const STORAGE_KEY = "keating_artifact_panel_width";
18	
19	function loadSavedWidth(): number {
20		if (typeof localStorage === "undefined") return DEFAULT_WIDTH;
21		try {
22			const raw = localStorage.getItem(STORAGE_KEY);
23			if (!raw) return DEFAULT_WIDTH;
24			const parsed = parseInt(raw, 10);
25			if (isNaN(parsed) || parsed < MIN_WIDTH || parsed > MAX_WIDTH) return DEFAULT_WIDTH;
26			return parsed;
27		} catch {
28			return DEFAULT_WIDTH;
29		}
30	}
31	
32	function saveWidth(value: number) {
33		try {
34			localStorage.setItem(STORAGE_KEY, String(value));
35		} catch {
36			/* noop */
37		}
38	}
39	
40	export function ArtifactSidePanel({ open, artifactId, onClose }: ArtifactSidePanelProps) {
41		const [width, setWidth] = useState(loadSavedWidth);
42		const dragState = useRef({ active: false, startX: 0, startWidth: 0 });
43	
44		useEffect(() => {
45			if (!open) return;
46			const onKeyDown = (event: KeyboardEvent) => {
47				if (event.key === "Escape") onClose();
48			};
49			window.addEventListener("keydown", onKeyDown);
50			return () => window.removeEventListener("keydown", onKeyDown);
51		}, [open, onClose]);
52	
53		const handleDragStart = useCallback((e: React.MouseEvent | React.TouchEvent) => {
54			e.preventDefault();
55			const clientX = "touches" in e ? e.touches[0].clientX : e.clientX;
56			dragState.current = { active: true, startX: clientX, startWidth: width };
57	
58			const onMove = (moveEvent: MouseEvent | TouchEvent) => {
59				if (!dragState.current.active) return;
60				const moveX = "touches" in moveEvent ? moveEvent.touches[0].clientX : moveEvent.clientX;
61				const delta = dragState.current.startX - moveX;
62				const nextWidth = Math.min(MAX_WIDTH, Math.max(MIN_WIDTH, dragState.current.startWidth + delta));
63				setWidth(nextWidth);
64			};
65	
66			const onUp = () => {
67				if (!dragState.current.active) return;
68				dragState.current.active = false;
69				document.body.style.cursor = "";
70				document.body.style.userSelect = "";
71				window.removeEventListener("mousemove", onMove);
72				window.removeEventListener("mouseup", onUp);
73				window.removeEventListener("touchmove", onMove);
74				window.removeEventListener("touchend", onUp);
75				setWidth((w) => {
76					saveWidth(w);
77					return w;
78				});
79			};
80	
81			document.body.style.cursor = "col-resize";
82			document.body.style.userSelect = "none";
83			window.addEventListener("mousemove", onMove);
84			window.addEventListener("mouseup", onUp);
85			window.addEventListener("touchmove", onMove, { passive: false });
86			window.addEventListener("touchend", onUp);
87		}, [width]);
88	
89		return (
90			<div className="relative flex h-full flex-col bg-background" style={{ width: `${width}px` }}>
91				{/* Resize handle — left edge drag bar */}
92				<div
93					className="group absolute inset-y-0 left-0 z-10 flex w-2 cursor-col-resize items-center justify-center"
94					onMouseDown={handleDragStart}
95					onTouchStart={handleDragStart}
96				>
97					<div className="h-8 w-0.5 rounded-full bg-border opacity-0 transition-opacity group-hover:opacity-100 group-active:opacity-100" />
98				</div>
99	
100				<div className="flex h-12 shrink-0 items-center justify-between gap-2 border-b border-border px-3">
101					<div className="flex items-center gap-2 min-w-0">
102						<Search size={14} className="shrink-0 text-muted-foreground" />
103						<span className="text-sm font-medium text-foreground truncate">Artifacts</span>
104					</div>
105					<button
106						type="button"
107						className="inline-flex h-7 w-7 items-center justify-center rounded-md transition-colors hover:bg-accent hover:text-accent-foreground"
108						aria-label="Close artifact panel"
109						title="Close panel"
110						onClick={onClose}
